/// pair.  Pushes nil and returns 1 when the traversal is exhausted.
///
/// C: `static int luaB_next(lua_State *L)`
pub(crate) fn next_fn(state: &mut LuaState) -> Result<usize, LuaError> {
    // C: luaL_checktype(L, 1, LUA_TTABLE);
