289	///   - Nil never equals anything (handled at call sites)
290	///   - Bool/Int/Float/String compare by value
291	///   - Int <-> Float compare numerically (Lua coerces)
292	///   - Table/Function/UserData/Thread compare by GcRef identity
293	fn lua_key_eq(a: &LuaValue, b: &LuaValue) -> bool {
294	    match (a, b) {
295	        (LuaValue::Nil, LuaValue::Nil) => true,
296	        (LuaValue::Bool(x), LuaValue::Bool(y)) => x == y,
297	        (LuaValue::Int(x), LuaValue::Int(y)) => x == y,
298	        (LuaValue::Float(x), LuaValue::Float(y)) => x == y,
299	        (LuaValue::Int(i), LuaValue::Float(f)) | (LuaValue::Float(f), LuaValue::Int(i)) => *f == *i as f64,
300	        (LuaValue::Str(x), LuaValue::Str(y)) => x.as_bytes() == y.as_bytes(),
301	        (LuaValue::Table(x), LuaValue::Table(y)) => GcRef::ptr_eq(x, y),
302	        (LuaValue::UserData(x), LuaValue::UserData(y)) => GcRef::ptr_eq(x, y),
303	        (LuaValue::Thread(x), LuaValue::Thread(y)) => GcRef::ptr_eq(x, y),
304	        (LuaValue::Function(x), LuaValue::Function(y)) => closure_eq(x, y),
305	        (LuaValue::LightUserData(x), LuaValue::LightUserData(y)) => x == y,
306	        _ => false,
307	    }
